args.sparql:
SELECT ?ethnicGroup WHERE {
  ?item rdfs:label "Shahsevan"@en;
  wdt:P170 ?ethnicGroup.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

SELECT DISTINCT ?item WHERE {
  ?item wdt:P17 wd:Q163;
         wdt:P135 wd:Q1093;
         rdfs:label ?label.
  FILTER(LANG(?label) = 'en' && ?label = 'Shahsevan')
}

SELECT ?ethnicGroupLabel WHERE {
  wd:Q327820 wdt:P135 ?ethnicGroup.
  ?ethnicGroup rdfs:label ?ethnicGroupLabel.
  FILTER (LANG(?ethnicGroupLabel) = 'en')
}

SELECT ?groupLabel WHERE {
  wd:Q1154862 wdt:P179 wd:Q7879;
              rdfs:label ?groupLabel.
  FILTER (LANG(?groupLabel) = 'en')
}
